import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.util.Date;

class DefaultDateTypeAdapterTest {

    private DefaultDateTypeAdapter<Date> adapter;
    private DefaultDateTypeAdapter.DateType<Date> dateType;

    @BeforeEach
    void setUp() {
        dateType = mock(DefaultDateTypeAdapter.DateType.class);
        adapter = new DefaultDateTypeAdapter<>(dateType, "yyyy-MM-dd");
    }

    @Test
    void testRead_NullToken() throws IOException {
        JsonReader jsonReader = mock(JsonReader.class);
        when(jsonReader.peek()).thenReturn(JsonToken.NULL);

        doNothing().when(jsonReader).nextNull();

        Date result = adapter.read(jsonReader);

        verify(jsonReader).peek();
        verify(jsonReader).nextNull();
        assertNull(result);
    }

    @Test
    void testRead_ValidDate() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        JsonReader jsonReader = mock(JsonReader.class);
        when(jsonReader.peek()).thenReturn(JsonToken.STRING);

        // Use reflection to invoke private deserializeToDate method
        Method deserializeMethod = DefaultDateTypeAdapter.class.getDeclaredMethod("deserializeToDate", JsonReader.class);
        deserializeMethod.setAccessible(true);

        // Mock the deserializeToDate method by spying the adapter
        DefaultDateTypeAdapter<Date> spyAdapter = Mockito.spy(adapter);

        Date expectedDate = new Date();
        doReturn(expectedDate).when(spyAdapter).deserializeToDate(jsonReader);
        when(dateType.deserialize(expectedDate)).thenReturn(expectedDate);

        Date result = spyAdapter.read(jsonReader);

        verify(jsonReader).peek();
        verify(spyAdapter).deserializeToDate(jsonReader);
        verify(dateType).deserialize(expectedDate);
        assertEquals(expectedDate, result);
    }
}
